input.data:
--jinja
Content-Disposition: form-data; name="comment"

{% set notes = [] %}
{% if CTX.resolution_note | d %}
  {% do notes.append("Resolution Note: " ~ CTX.resolution_note) %}
{% endif %}
{% if CTX.external_note | d %}
  {% do notes.append(CTX.external_note) %}
{% endif %}
{% if CTX.internal_note | d %}
  {% do notes.append(CTX.internal_note) %}
{% endif %}

{
  "public": {{ (CTX.public_value | default(false)) | string | lower }},
  "body": {{ notes | join('\n\n') | default('') | tojson }},
  "htmlBody": {{ ("<p>" ~ (notes | join('<br><br>') | default('')) ~ "</p>") | tojson }},
  "duplicateInIncidents": true
}


--jinja--

