input.raw_query:
query {
  getTicketList(input: {
    condition: {
      joinOperator: "AND"
      operands: [
        {
          attribute: "status"
          operator: "isNot"
          value: "Closed"
        },
        {
          attribute: "ticketId"
          operator: "is"
          value: {{ CTX.ticket_id|d }}
        }
      ]
    }
  }) {
    tickets {
      ticketId
      displayId
      subject
      ticketType
      requestType
      source
      client
      site
      requester
      additionalRequester
      followers
      techGroup
      technician
      status
      priority
      impact
      urgency
      category
      subcategory
      cause
      subcause
      resolutionCode
      sla
      createdTime
      updatedTime
      firstResponseDueTime
      firstResponseTime
      firstResponseViolated
      resolutionDueTime
      resolutionTime
      resolutionViolated
      customFields
      worklogTimespent
    }
    listInfo {
      totalCount
      hasMore
    }
  }
}

