{%- set purchase_list = [] -%}
{%- set seen_skus = [] -%}
{%- for v in CTX.count_violations -%}
  {%- if v.skuId not in seen_skus -%}
    {%- do seen_skus.append(v.skuId) -%}
    {%- set sku_info = (CTX.subscribed_skus | selectattr("skuId", "eq", v.skuId) | list) -%}
    {%- if sku_info -%}
      {%- set available = sku_info[0].prepaidUnits.enabled|int - sku_info[0].consumedUnits|int -%}
      {%- set qty_needed = (1 - available) if available < 1 else 1 -%}
      {%- do purchase_list.append({"skuId": v.skuId, "assignedByGroup": v.assignedByGroup, "delta_quantity": qty_needed}) -%}
    {%- endif -%}
  {%- endif -%}
{%- endfor -%}
